const data = $input.first().json.body || $input.first().json;
const platform = (data.source_platform || '').toLowerCase();

let scriptName;
if (platform.includes('linkedin')) {
  scriptName = 'linkedin_apply.js';
} else {
  // WTTJ, EuroJobs, Indeed EU — use LinkedIn script as base (handles general apply flows)
  scriptName = 'linkedin_apply.js';
}

// Always ensure cover letter is included for EU applications
const coverLetterPath = data.coverLetterPath || '';

return [{ json: { ...data, scriptName, coverLetterPath, is_eu_application: true } }];

const stdout = $input.first().json.stdout || '';
const prev = $('EU Platform Router').first().json;

let result;
try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  result = jsonMatch ? JSON.parse(jsonMatch[0]) : { success: false, error: 'No JSON in output' };
} catch (e) {
  result = { success: false, error: `Parse error: ${e.message}` };
}

return [{
  json: {
    ...prev,
    apply_success: result.success,
    screenshot_path: result.screenshot || '',
    error_message: result.error || '',
    status: result.success ? 'APPLIED' : 'FAILED'
  }
}];
